import{c as t,Q as e,j as a,m as l}from"./chunks/framework.BIBjCrbN.js";const p=JSON.parse('{"title":"浙江大学","description":"浙江大学求是高等研究院/脑机智能全国重点实验室博士项目指南 — BCI方向导师信息与申请流程","frontmatter":{"title":"浙江大学","description":"浙江大学求是高等研究院/脑机智能全国重点实验室博士项目指南 — BCI方向导师信息与申请流程","data-collected":"2026-05-25T00:00:00.000Z","related-directions":["bci","bme","neuroscience"],"tags":["浙江大学","杭州",985,"C9"],"admission-year":2027},"headers":[],"relativePath":"universities/zju.md","filePath":"universities/zju.md","lastUpdated":1780110618000}'),n={name:"universities/zju.md"};function o(i,r,s,h,g,u){return e(),a("div",null,[...r[0]||(r[0]=[l('<h1 id="浙江大学" tabindex="-1">浙江大学 <a class="header-anchor" href="#浙江大学" aria-label="Permalink to &quot;浙江大学&quot;">​</a></h1><blockquote><p><strong>最后更新</strong>: 2026年5月25日</p></blockquote><h2 id="学校概况" tabindex="-1">学校概况 <a class="header-anchor" href="#学校概况" aria-label="Permalink to &quot;学校概况&quot;">​</a></h2><p>浙江大学在脑机接口领域拥有国内最强的研究力量之一，依托<strong>脑机智能全国重点实验室</strong>和<strong>求是高等研究院</strong>，在植入式BCI、脑机混合智能、神经调控等方向处于国际前沿。</p><p><strong>官方链接</strong>:</p><ul><li>学校官网: <a href="https://www.zju.edu.cn" target="_blank" rel="noreferrer">https://www.zju.edu.cn</a></li><li>研究生院: <a href="https://grs.zju.edu.cn" target="_blank" rel="noreferrer">https://grs.zju.edu.cn</a></li><li>脑机智能全国重点实验室: [相关页面]</li><li>求是高等研究院: [相关页面]</li></ul><h2 id="相关学院" tabindex="-1">相关学院 <a class="header-anchor" href="#相关学院" aria-label="Permalink to &quot;相关学院&quot;">​</a></h2><p>浙大BCI方向的导师分布在多个学院：</p><ul><li><strong>计算机科学与技术学院</strong> — 潘纲、郑能干等（脑机接口算法/系统）</li><li><strong>生物医学工程与仪器科学学院</strong> — 张韶岷等（植入式BCI设备）</li><li><strong>集成电路学院</strong> — 赵博等（脑机接口芯片硬件）</li><li><strong>医学院</strong> — 神经科学与临床转化</li></ul><hr><h2 id="重点课题组与导师" tabindex="-1">重点课题组与导师 <a class="header-anchor" href="#重点课题组与导师" aria-label="Permalink to &quot;重点课题组与导师&quot;">​</a></h2><h3 id="——-脑机接口-神经工程方向-——" tabindex="-1">—— 脑机接口 / 神经工程方向 —— <a class="header-anchor" href="#——-脑机接口-神经工程方向-——" aria-label="Permalink to &quot;—— 脑机接口 / 神经工程方向 ——&quot;">​</a></h3><h4 id="潘纲-—-教授、求是特聘教授、博导" tabindex="-1">潘纲 — 教授、求是特聘教授、博导 <a class="header-anchor" href="#潘纲-—-教授、求是特聘教授、博导" aria-label="Permalink to &quot;潘纲 — 教授、求是特聘教授、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 计算机科学与技术学院</li><li><strong>身份</strong>: <strong>脑机智能全国重点实验室主任</strong>、国家杰出青年基金获得者</li><li><strong>个人主页</strong>: <a href="https://person.zju.edu.cn/gpan" target="_blank" rel="noreferrer">https://person.zju.edu.cn/gpan</a></li><li><strong>邮箱</strong>: <a href="mailto:gpan@zju.edu.cn" target="_blank" rel="noreferrer">gpan@zju.edu.cn</a></li></ul><p><strong>研究方向</strong>:</p><ul><li>人工智能</li><li>脑机接口（算法与系统）</li><li>类脑计算</li><li>普适计算</li></ul><p><strong>学术地位</strong>: 国内BCI领域的核心领军人物，领导脑机智能全国重点实验室。</p><p><strong>2026年博士生招生</strong>: 待确认</p><hr><h4 id="张韶岷-—-研究员、博导" tabindex="-1">张韶岷 — 研究员、博导 <a class="header-anchor" href="#张韶岷-—-研究员、博导" aria-label="Permalink to &quot;张韶岷 — 研究员、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 生物医学工程与仪器科学学院</li><li><strong>个人主页</strong>: <a href="https://person.zju.edu.cn/%E7%9B%B8%E5%85%B3%E9%93%BE%E6%8E%A5" target="_blank" rel="noreferrer">浙江大学个人主页</a></li></ul><p><strong>研究方向</strong>:</p><ul><li><strong>植入式脑机接口</strong> — 核心方向</li><li>无创神经调控技术</li><li>神经工程</li></ul><p><strong>学术成果</strong>: 长期从事植入式脑机接口和神经调控技术，成果曾入选<strong>教育部高校十大科技进展</strong>。</p><p><strong>2026年博士生招生</strong>: 待确认</p><hr><h4 id="郑能干-—-教授、博导" tabindex="-1">郑能干 — 教授、博导 <a class="header-anchor" href="#郑能干-—-教授、博导" aria-label="Permalink to &quot;郑能干 — 教授、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 计算机科学与技术学院</li><li><strong>个人主页</strong>: <a href="https://person.zju.edu.cn/nengganzheng" target="_blank" rel="noreferrer">https://person.zju.edu.cn/nengganzheng</a></li></ul><p><strong>研究方向</strong>:</p><ul><li>脑机混合智能</li><li>脑机接口</li><li>动物机器人</li><li>智能嵌入式系统</li></ul><p><strong>2026年博士生招生</strong>: 待确认</p><hr><h4 id="赵博-—-长聘教授、求是特聘教授、博导" tabindex="-1">赵博 — 长聘教授、求是特聘教授、博导 <a class="header-anchor" href="#赵博-—-长聘教授、求是特聘教授、博导" aria-label="Permalink to &quot;赵博 — 长聘教授、求是特聘教授、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 集成电路学院（副院长）</li><li><strong>个人主页</strong>: <a href="https://person.zju.edu.cn/zhaobo" target="_blank" rel="noreferrer">https://person.zju.edu.cn/zhaobo</a></li></ul><p><strong>研究方向</strong>:</p><ul><li><strong>脑机接口芯片</strong> — 核心方向</li><li>智能生物医疗芯片</li><li>近零功耗无线通信芯片</li></ul><p><strong>特色</strong>: 侧重脑机接口的硬件/芯片方向，适合有工程背景的申请人。</p><p><strong>2026年博士生招生</strong>: 待确认</p><hr><h4 id="庄柳静-—-百人计划研究员、博导" tabindex="-1">庄柳静 — 百人计划研究员、博导 <a class="header-anchor" href="#庄柳静-—-百人计划研究员、博导" aria-label="Permalink to &quot;庄柳静 — 百人计划研究员、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 生仪学院</li><li><strong>个人主页</strong>: <a href="https://person.zju.edu.cn/0617206" target="_blank" rel="noreferrer">https://person.zju.edu.cn/0617206</a></li></ul><p><strong>研究方向</strong>:</p><ul><li>仿生嗅觉与味觉传感</li><li><strong>嗅觉脑机接口</strong> — 特色方向</li><li>类脑智能</li></ul><p><strong>2026年博士生招生</strong>: 待确认</p><hr><h4 id="江海腾-—-研究员、博导" tabindex="-1">江海腾 — 研究员、博导 <a class="header-anchor" href="#江海腾-—-研究员、博导" aria-label="Permalink to &quot;江海腾 — 研究员、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 相关学院</li><li><strong>个人主页</strong>: <a href="https://person.zju.edu.cn/HaitengJiang" target="_blank" rel="noreferrer">https://person.zju.edu.cn/HaitengJiang</a></li></ul><p><strong>研究方向</strong>:</p><ul><li>医学大数据AI</li><li>神经工程</li><li>计算神经科学</li><li>脑科学与认知神经科学</li></ul><p><strong>2026年博士生招生</strong>: 待确认</p><hr><h2 id="_2026年博士招生" tabindex="-1">2026年博士招生 <a class="header-anchor" href="#_2026年博士招生" aria-label="Permalink to &quot;2026年博士招生&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">待公布</p><p>浙江大学2026年博士招生简章通常于<strong>2025年9-10月</strong>发布。以下为往年参考时间线。</p></div><h3 id="申请时间-预估" tabindex="-1">申请时间（预估） <a class="header-anchor" href="#申请时间-预估" aria-label="Permalink to &quot;申请时间（预估）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>时间</th><th>说明</th></tr></thead><tbody><tr><td>招生简章发布</td><td>2025年10月</td><td>浙大研招网公布</td></tr><tr><td>网上报名</td><td>2025年10月-11月</td><td>通过浙大研究生招生系统</td></tr><tr><td>材料审核</td><td>2025年11月-12月</td><td>学院组织</td></tr><tr><td>综合考核</td><td>2026年3月-4月</td><td>笔试+面试</td></tr></tbody></table><h3 id="招生方式" tabindex="-1">招生方式 <a class="header-anchor" href="#招生方式" aria-label="Permalink to &quot;招生方式&quot;">​</a></h3><p><strong>申请-考核制</strong>，部分专业接收直博生和硕博连读生。</p><h3 id="考核方式-参考" tabindex="-1">考核方式（参考） <a class="header-anchor" href="#考核方式-参考" aria-label="Permalink to &quot;考核方式（参考）&quot;">​</a></h3><ul><li>材料审核：学术背景、科研成果、研究计划</li><li>笔试：专业综合（部分学院）</li><li>面试：研究计划汇报 + 专家提问（含英语）</li></ul><hr><h2 id="针对你的申请建议" tabindex="-1">针对你的申请建议 <a class="header-anchor" href="#针对你的申请建议" aria-label="Permalink to &quot;针对你的申请建议&quot;">​</a></h2><ol><li><strong>潘纲教授是最佳匹配目标之一</strong>：作为脑机智能全国重点实验室主任，领导国内最大的BCI研究平台之一，你的帝国理工神经技术背景高度匹配</li><li><strong>多学院选择策略</strong>：可根据个人偏好选择侧重算法的计算机学院或侧重硬件的生仪学院/集成电路学院</li><li><strong>提前联系导师尤为重要</strong>：浙大BCI方向竞争激烈，建议2025年7-8月发送联系邮件</li><li><strong>脑机接口芯片方向</strong>：赵博教授侧重芯片硬件，你的电路设计经验（EMG项目）可作切入点</li><li><strong>张韶岷研究员</strong>的植入式BCI方向与你的脑类器官/神经技术背景可能有交叉点</li></ol><hr><h2 id="信息来源" tabindex="-1">信息来源 <a class="header-anchor" href="#信息来源" aria-label="Permalink to &quot;信息来源&quot;">​</a></h2><ul><li><a href="https://person.zju.edu.cn/gpan" target="_blank" rel="noreferrer">潘纲教授主页</a>（访问日期: 2026-05-25）</li><li><a href="https://person.zju.edu.cn/nengganzheng" target="_blank" rel="noreferrer">郑能干教授主页</a>（访问日期: 2026-05-25）</li><li><a href="https://grs.zju.edu.cn" target="_blank" rel="noreferrer">浙大研究生院</a>（访问日期: 2026-05-25）</li></ul><hr><p><em>本页面信息采集于2026年5月，请以浙江大学研究生院官网最新公告为准。</em></p><p><em>下次更新建议: 2026年8月（2027年入学申请季开始前）</em></p>',68)])])}const c=t(n,[["render",o]]);export{p as __pageData,c as default};
